const body = $input.item.json.body || $input.item.json;
const order = body.record || body;

if (!order || Object.keys(order).length === 0) {
  throw new Error('❌ No se recibieron datos del pedido');
}

function validarTelefono(phone) {
  if (!phone) return false;
  const regex = /^(\+51|51)?9\d{8}$/;
  return regex.test(phone.replace(/\s/g, '').replace(/-/g, ''));
}

function normalizarTelefono(phone) {
  const cleaned = phone.replace(/\s/g, '').replace(/-/g, '');
  if (cleaned.startsWith('+51')) return cleaned;
  if (cleaned.startsWith('51')) return '+' + cleaned;
  if (cleaned.startsWith('9')) return '+51' + cleaned;
  return phone;
}

function validarEmail(email) {
  if (!email) return false;
  const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return regex.test(email);
}

const errores = [];

if (!order.customer_name || order.customer_name.trim() === '') {
  errores.push('Nombre del cliente es obligatorio');
}

if (!order.customer_phone || !validarTelefono(order.customer_phone)) {
  errores.push('Teléfono inválido');
}

if (!order.customer_email || !validarEmail(order.customer_email)) {
  errores.push('Email inválido');
}

if (!order.total_amount || order.total_amount <= 0) {
  errores.push('Monto total inválido');
}

if (!order.items || !Array.isArray(order.items) || order.items.length === 0) {
  errores.push('El pedido debe tener al menos un producto');
}

if (errores.length > 0) {
  return {
    json: {
      ...order,
      error: errores.join(', '),
      has_error: true
    }
  };
}

const phoneNormalized = normalizarTelefono(order.customer_phone);
const orderNumber = order.id ? order.id.substring(0, 8).toUpperCase() : 'ORD-' + Date.now().toString().substring(7);
const formattedTotal = `S/ ${parseFloat(order.total_amount).toFixed(2)}`;
const firstName = order.customer_name.split(' ')[0];

let totalItems = 0;
if (order.items && Array.isArray(order.items)) {
  totalItems = order.items.reduce((sum, item) => sum + (parseInt(item.quantity) || 0), 0);
}

const orderDate = new Date(order.created_at || Date.now()).toLocaleString('es-PE', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

const deliveryTime = new Date(Date.now() + 45 * 60000).toLocaleTimeString('es-PE', {
  hour: '2-digit',
  minute: '2-digit',
  hour12: true
});

return {
  json: {
    ...order,
    customer_phone_normalized: phoneNormalized,
    order_number: orderNumber,
    formatted_total: formattedTotal,
    customer_first_name: firstName,
    total_items: totalItems,
    order_date: orderDate,
    delivery_time: deliveryTime,
    status: order.status || 'Pendiente',
    has_error: false
  }
};

const order = $input.item.json;

let productListWhatsApp = '';
if (order.items && Array.isArray(order.items)) {
  productListWhatsApp = order.items.map((item, index) => {
    const subtotal = (parseFloat(item.price || item.unit_price || 0) * parseInt(item.quantity || 0)).toFixed(2);
    return `  ${index + 1}. ${item.name || item.product_name} x${item.quantity}\n     S/ ${subtotal}`;
  }).join('\n\n');
}

let productListHTML = '';
if (order.items && Array.isArray(order.items)) {
  productListHTML = order.items.map((item, index) => {
    const unitPrice = parseFloat(item.price || item.unit_price || 0);
    const quantity = parseInt(item.quantity || 0);
    const subtotal = (unitPrice * quantity).toFixed(2);
    return `
    <tr>
      <td style="padding: 10px; border-bottom: 1px solid #e5e7eb;">${index + 1}</td>
      <td style="padding: 10px; border-bottom: 1px solid #e5e7eb; font-weight: 500;">${item.name || item.product_name}</td>
      <td style="padding: 10px; border-bottom: 1px solid #e5e7eb; text-align: center;">${quantity}</td>
      <td style="padding: 10px; border-bottom: 1px solid #e5e7eb; text-align: right;">S/ ${unitPrice.toFixed(2)}</td>
      <td style="padding: 10px; border-bottom: 1px solid #e5e7eb; text-align: right; font-weight: 600; color: #059669;">S/ ${subtotal}</td>
    </tr>`;
  }).join('');
}

let productListSimple = '';
if (order.items && Array.isArray(order.items)) {
  productListSimple = order.items.map((item, index) => {
    const subtotal = (parseFloat(item.price || item.unit_price || 0) * parseInt(item.quantity || 0)).toFixed(2);
    return `${index + 1}. ${item.name || item.product_name} x${item.quantity} - S/ ${subtotal}`;
  }).join('\n');
}

let fullAddress = order.shipping_address || 'Dirección no especificada';
if (typeof order.shipping_address === 'object' && order.shipping_address !== null) {
  const addr = order.shipping_address;
  const parts = [addr.street, addr.district, addr.city, addr.postal_code].filter(p => p && p.trim() !== '');
  fullAddress = parts.length > 0 ? parts.join(', ') : 'Dirección no especificada';
}

const reference = (typeof order.shipping_address === 'object' && order.shipping_address?.reference) ? order.shipping_address.reference : '';

return {
  json: {
    ...order,
    product_list_whatsapp: productListWhatsApp,
    product_list_html: productListHTML,
    product_list_simple: productListSimple,
    full_address: fullAddress,
    address_reference: reference
  }
};

