  if (!phone) return '';
  const cleaned = phone.replace(/\s/g, '').replace(/-/g, '');
  if (cleaned.startsWith('+51')) return cleaned;
  if (cleaned.startsWith('51')) return '+' + cleaned;
  if (cleaned.startsWith('9')) return '+51' + cleaned;
  return phone;
}

// Normalizar datos
