const statusChangeDate = new Date().toLocaleString('es-PE', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

// Mensajes personalizados según el estado
let statusMessage = '';
let statusEmoji = '';
let statusColor = '';

if (newStatus === 'Completado') {
  statusMessage = '¡Tu pedido ha sido completado y está en camino!';
  statusEmoji = '✅';
  statusColor = '#059669';
} else if (newStatus === 'Cancelado') {
  statusMessage = 'Tu pedido ha sido cancelado.';
  statusEmoji = '❌';
  statusColor = '#ef4444';
} else if (newStatus === 'Pendiente') {
  statusMessage = 'Tu pedido está siendo procesado.';
  statusEmoji = '⏳';
  statusColor = '#f59e0b';
